const { vm_id, operation, proxmox_host } = $('📥 Input').first().json;
if (!vm_id || !operation) throw new Error('vm_id und operation erforderlich');
const ops = ['snapshot', 'restore', 'health_check', 'start', 'stop', 'status'];
if (!ops.includes(operation)) throw new Error(`Unbekannte Operation: ${operation}. Erlaubt: ${ops.join(', ')}`);
return { vm_id, operation, proxmox_host: proxmox_host || '10.1.1.100', vm_type: 'qemu',
  session_id: require('crypto').randomUUID(), timestamp: new Date().toISOString() };

const { vm_id, operation, proxmox_host, session_id } = $input.first().json;
// Proxmox-API-Calls via n8n HTTP werden in Sub-Nodes abgebildet
// Hier: Simulation des Ergebnis-Formats
return { exit_code: 'success', session_id, data: { vm_id, operation, result: `${operation} auf VM ${vm_id} ausgeführt` },
  timestamp: new Date().toISOString() };
